class Solution:
    def minOperations(self, nums, k):
        if min(nums) < k:
            return -1
        return len(set(v for v in nums if v > k))

solutions.javascript:
var minOperations = function(nums, k) {
    let mn = Infinity;
    const above = new Set();
    for (const v of nums) {
        if (v < mn) mn = v;
        if (v > k) above.add(v);
    }
    if (mn < k) return -1;
    return above.size;
};
